INSERT INTO `products` VALUES (1,'Laptop gaming Acer Nitro ProPanel ANV16S-61-R7KQ','##\nLaptop gaming Acer Nitro ANV16S-61-R7KQ - Sức mạnh AI trong tầm tay bạn\nLaptop gaming Acer Nitro ANV16S-61-R7KQ là người bạn đồng hành đắc lực cho các bạn yêu thích game và sáng tạo nội dung. Máy được trang bị con chip AMD Ryzen AI 5 340 với sức mạnh AI lên đến 50 TOPS, giúp cho mọi thao tác trên máy đều nhanh và mượt mà hơn bao giờ hết. Dù bạn đang chơi những tựa game nặng hay làm việc đa nhiệm, chiếc máy này đều có thể đáp ứng tốt.\nHiệu năng mạnh mẽ, thoải mái nâng cấp\nVới 16GB RAM DDR5 siêu nhanh và ổ cứng SSD 512GB PCIe NVMe, bạn sẽ có trải nghiệm đa nhiệm mượt mà và tốc độ xử lý cực nhanh. Điều thú vị là máy còn có 2 khe RAM và 2 khe SSD cho phép bạn dễ dàng nâng cấp lên đến 96GB RAM và 4TB SSD trong tương lai, đảm bảo máy luôn theo kịp nhu cầu sử dụng.\nMàn hình rộng sắc nét, sống động\nMàn hình 16 inch FHD+ với tần số quét 180Hz và thời gian phản hồi 3ms mang đến hình ảnh cực mượt, siêu rõ nét, giúp bạn trải nghiệm game hay xem phim đều rất đã mắt. Ngoài ra, tấm nền IPS chuẩn sRGB 100% tái hiện màu sắc chuẩn xác, góc nhìn rộng cho công việc thiết kế hay giải trí đều tuyệt vời.\nThiết kế cá tính, bàn phím RGB ấn tượng\nChiếc \nlaptop Acer\n có tông màu đen thể thao cùng vỏ nhôm chắc chắn, đậm chất gaming. Bàn phím được trang bị đèn 4-zone RGB có thể tùy chỉnh theo ý thích, giúp không gian làm việc hay chơi game thêm phần sinh động. Hệ thống tản nhiệt Dual-Fan mạnh mẽ hỗ trợ giữ máy luôn mát ngay cả khi bạn chơi game hay làm việc liên tục.\nPin bền bỉ và kết nối hiện đại\nViên pin 76Wh 4-cell Li-ion cho thời gian sử dụng lâu dài cùng bộ sạc nhanh 135W sẽ giữ máy luôn trong tình trạng sẵn sàng hoạt động. Bên cạnh đó, việc trang bị kết nối Wi-Fi 6E mới nhất cũng hỗ trợ bạn chơi game online hay làm việc trực tuyến mượt mà, ổn định.',NULL,'Laptop gaming Acer Nitro ANV16S-61-R7KQ - Sức mạnh AI trong tầm tay bạn',1200.00,'ACER','2026-03-25 08:23:37','2026-03-25 18:27:10','LAPTOP',0,0,0),(2,'Laptop gaming Acer Nitro V 15 ANV15 41 R1JY','✔ Bảo hành chính hãng 24 tháng. \n✔ Hỗ trợ đổi mới trong 7 ngày. \n✔ Miễn phí giao hàng toàn quốc.\nQuà tặng:\n?Balo Acer SUV\nHỗ trợ trả góp MPOS (Thẻ tín dụng), HDSAISON (\nXem chi tiết\n).\n##\nThông số kỹ thuật:\nCPU\nAMD Ryzen™ 5 6600H ( 6 Nhân, 12 Luồng, Up to 4.5 GHz) 3 MB L2 cache, up to 16 MB L3 cache\nRam\n16GB (1x16GB) DDR5 4800MHz (2x SO-DIMM socket, up to 96GB SDRAM)\nỔ cứng\n512GB PCIe NVMe SSD (Còn trống 1 khe SSD M.2 PCIE, nâng cấp tối đa 4TB)\nCard đồ họa\nNVIDIA® GeForce RTX™ 3050 with 6GB of dedicated GDDR6 VRAM\nMàn hình\n15.6\" FHD IPS 165Hz 45% NTSC 300nits, \"Acer ComfyView™ LED-backlit TFT LCD 16:9 aspect ratio, supporting 144 Hz refresh rate. Wide viewing angle up to 170 degrees ,Ultra-slim design\nCổng giao tiếp\nUSB Type-C\n USB Type-C™ port supporting: \n • USB4® 40Gbps \n • DisplayPort over USB-C \n • USB charging 5 V; 3 A \n • DC-in port 20 V; 65 W \n \n USB Standard A \n Three USB Standard-A ports, supporting: \n • One port for USB 3.2 Gen 1 featuring power off USB charging\n • Two ports for USB 3.2 Gen 1 \n \n HDMI® 2.1 port with HDCP support \n 3.5 mm headphone/speaker jack, supporting headsets with built-in microphone \n Ethernet (RJ-45) port \n DC-in jack for AC adapter\nAudio\nDTS® X:Ultra Audio, featuring optimized Bass, Loudness, Speaker Protection with up to 6 custom content modes by smart amplifier \nBàn phím\nCó đèn bàn phím\nĐọc thẻ nhớ\nNone\nChuẩn LAN\nGigabit Ethernet\nChuẩn WIFI\n802.11a/b/g/n/ac+ax wireless LAN\nDual Band (2.4 GHz and 5 GHz)\nBluetooth\nBluetooth® 5.1\nWebcam\n720p HD audio/video recording\nHệ điều hành\nWindows 11 Home\nPin\n57Whr 4-cell\n135W AC Adapter\nTrọng lượng\n2.1 kg\nMàu sắc\nObsidian Black\nChất liệu\nCover A, B, C, D: ABS Plastic\nKích thước\n362.3 (W) x 239.89 (D) x 23.5 (H) mm',NULL,'✔ Bảo hành chính hãng 24 tháng.',1100.00,'ACER','2026-03-25 08:23:37','2026-03-25 18:27:10','LAPTOP',0,0,0),(3,'Laptop gaming Acer Nitro ProPanel 